toolCalls.sql:
BEGIN;

SELECT oi.order_id, oi.product_id
FROM pellier.order_items oi
JOIN pellier.orders o ON o.order_id = oi.order_id
WHERE o.customer_id = $1
  AND oi.product_id = $2
LIMIT 1;

INSERT INTO pellier.returns (customer_id, product_id, reason, status)
VALUES ($1, $2, 'damaged', 'pending')
RETURNING return_id;

UPDATE pellier.product_catalog
SET quantity = quantity - 1
WHERE product_id = $2;

COMMIT;

